import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type UniformSize = 'S' | 'M' | 'L' | 'XL' | '2XL';

export interface StudentInfo {
  studentId: string;
  englishName: string;
  arabicName: string;
  grade: string;
  className: string; // mapped from 'class' in requirements
}

export interface UniformRequest {
  shirt: UniformSize | '';
  trousers: UniformSize | '';
  jacket: UniformSize | '';
  notes: string;
}

export interface AdminRequestRow extends StudentInfo {
  row: number;
  shirt: UniformSize;
  trousers: UniformSize;
  jacket: UniformSize;
  notes: string;
  requestStatus: 'Pending' | 'Approved';
}

export enum AppMode {
  STUDENT = 'student',
  ADMIN = 'admin'
}

export const SCHOOL_NAME = "Knowledge Towers School (KTS)";
export const PRIMARY_BLUE = "#1E3A8A";

// IMPORTANT: Replace this with your actual Google Apps Script Web App URL
export const API_BASE_URL = "YOUR_WEB_APP_URL";

export const UNIFORM_SIZES = ['S', 'M', 'L', 'XL', '2XL'];

export const GRADES = [
  'Grade 1', 'Grade 2', 'Grade 3', 'Grade 4', 'Grade 5',
  'Grade 6', 'Grade 7', 'Grade 8', 'Grade 9', 'Grade 10',
  'Grade 11', 'Grade 12'
];

import { StudentInfo, AdminRequestRow, UniformRequest } from '../types';
import { API_BASE_URL } from '../constants';

/**
 * Note: These calls target the YOUR_WEB_APP_URL provided in the prompt.
 * It assumes a Google Apps Script or similar backend structure.
 */

export const searchStudent = async (studentId: string): Promise<StudentInfo | null> => {
  try {
    const url = `${API_BASE_URL}?action=search&studentId=${encodeURIComponent(studentId)}`;
    const response = await fetch(url);
    const data = await response.json();

    // Check if student was found based on standard API patterns
    if (data && data.englishName) {
      return {
        studentId: data.studentId || studentId,
        englishName: data.englishName,
        arabicName: data.arabicName,
        grade: data.grade,
        className: data.class // mapped from 'class'
      };
    }
    return null;
  } catch (error) {
    console.error("Error searching student:", error);
    throw error;
  }
};

export const submitRequest = async (
  student: StudentInfo, 
  request: UniformRequest
): Promise<{ success: boolean; message?: string }> => {
  try {
    const payload = {
      action: "requestUpdate",
      studentId: student.studentId,
      englishName: student.englishName,
      grade: student.grade,
      class: student.className,
      shirt: request.shirt,
      trousers: request.trousers,
      jacket: request.jacket,
      notes: request.notes
    };

    const response = await fetch(API_BASE_URL, {
      method: 'POST',
      body: JSON.stringify(payload)
    });

    const data = await response.json();
    return { 
      success: data.status === 'success', 
      message: data.message 
    };
  } catch (error) {
    console.error("Error submitting request:", error);
    throw error;
  }
};

export const fetchAdminRequests = async (password: string): Promise<AdminRequestRow[]> => {
  try {
    const url = `${API_BASE_URL}?action=admin&password=${encodeURIComponent(password)}`;
    const response = await fetch(url);
    const data = await response.json();

    if (Array.isArray(data)) {
        return data.map((item: any) => ({
            ...item,
            className: item.class // mapping 'class' key
        }));
    }

    if (data.status === 'error') {
        throw new Error(data.message || "Unauthorized");
    }

    return [];
  } catch (error) {
    console.error("Error fetching admin requests:", error);
    throw error;
  }
};

export const approveRequest = async (row: number, password: string): Promise<boolean> => {
  try {
    const payload = {
      action: "approve",
      row: row,
      password: password
    };

    const response = await fetch(API_BASE_URL, {
      method: 'POST',
      body: JSON.stringify(payload)
    });

    const data = await response.json();
    return data.status === 'success';
  } catch (error) {
    console.error("Error approving request:", error);
    throw error;
  }
};

