import React, { useState } from 'react';
import { StudentInfo, UniformRequest, UniformSize } from '../types';
import { UNIFORM_SIZES, PRIMARY_BLUE } from '../constants';
import { User, ClipboardList, CheckCircle2, AlertCircle, Loader2 } from 'lucide-react';

interface RequestFormProps {
  student: StudentInfo;
  onSubmit: (request: UniformRequest) => Promise<void>;
  isSubmitting: boolean;
  status: 'idle' | 'success' | 'duplicate' | 'error';
}

