    shirt: '',
    trousers: '',
    jacket: '',
    notes: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(form);
  };

  const handleSizeChange = (field: keyof UniformRequest, value: string) => {
    setForm(prev => ({ ...prev, [field]: value }));
  };

  if (status === 'success') {
    return (
      <div className="bg-white rounded-2xl shadow-soft p-12 border border-green-100 text-center animate-in fade-in zoom-in duration-300">
        <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle2 className="h-10 w-10 text-green-500" />
        </div>
        <h3 className="text-2xl font-bold text-gray-900 mb-2">Request Submitted!</h3>
        <p className="text-gray-600 mb-8 max-w-md mx-auto">
          Thank you, {student.englishName}. Your uniform size request has been recorded and is currently pending approval.
        </p>
        <button 
          onClick={() => window.location.reload()}
          className="text-blue-600 font-semibold hover:underline"
        >
          Submit another request
        </button>
