      {/* Student Info Card */}
      <div className="bg-white rounded-2xl shadow-soft border border-gray-100 overflow-hidden">
        <div className="bg-blue-50/50 px-8 py-4 border-b border-blue-50 flex items-center gap-3">
          <User className="h-5 w-5 text-blue-600" />
          <h3 className="font-semibold text-blue-900">Student Profile</h3>
        </div>
        <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-1">
            <p className="text-xs uppercase tracking-wider text-gray-400 font-bold">English Name</p>
            <p className="text-lg font-semibold text-gray-900">{student.englishName}</p>
          </div>
          <div className="space-y-1 text-right md:text-left">
            <p className="text-xs uppercase tracking-wider text-gray-400 font-bold">Arabic Name | الإسم بالعربي</p>
            <p className="text-lg font-semibold text-gray-900 font-arabic" dir="rtl">{student.arabicName}</p>
          </div>
          <div className="space-y-1">
            <p className="text-xs uppercase tracking-wider text-gray-400 font-bold">Grade</p>
            <p className="text-gray-900">{student.grade}</p>
          </div>
          <div className="space-y-1">
            <p className="text-xs uppercase tracking-wider text-gray-400 font-bold">Class</p>
            <p className="text-gray-900">{student.className}</p>
          </div>
        </div>
      </div>

      {/* Uniform Form */}
      <form onSubmit={handleSubmit} className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100">
        <div className="flex items-center gap-3 mb-8">
          <ClipboardList className="h-6 w-6 text-gray-400" />
          <h2 className="text-xl font-bold text-gray-900">Uniform Specifications</h2>
        </div>

        {status === 'duplicate' && (
          <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-xl flex items-center gap-3 text-amber-800">
            <AlertCircle className="h-5 w-5 shrink-0" />
            <p className="text-sm">You have already submitted a request. Duplicate requests are not permitted.</p>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
