/**
 * Helper to handle fetch responses more robustly for Google Apps Script
 */
async function safeFetch(url: string, options: RequestInit = {}) {
  try {
    // We explicitly set the content type to text/plain for POST requests.
    // This makes it a "simple request" and prevents the browser from sending 
    // an OPTIONS (preflight) request, which Google Apps Script does not support.
    const fetchOptions: RequestInit = {
      mode: 'cors',
      redirect: 'follow',
      ...options,
    };

    if (options.method === 'POST') {
      fetchOptions.headers = {
        ...options.headers,
        'Content-Type': 'text/plain;charset=utf-8',
      };
    }

    const response = await fetch(url, fetchOptions);

    if (!response.ok) {
      throw new Error(`Network response was not ok (Status: ${response.status})`);
    }

    const text = await response.text();
    try {
      return JSON.parse(text);
    } catch (e) {
      console.error("Expected JSON but received non-JSON response:", text);
      if (text.includes('<!DOCTYPE html>')) {
        throw new Error("The script returned HTML. Ensure the deployment is set to 'Anyone' and you are using the 'Exec' URL.");
      }
      throw new Error("The server returned an invalid format.");
    }
  } catch (error: any) {
    console.error("API Call failed:", error);
    // Improve error message for the UI
    if (error.message === 'Failed to fetch') {
      throw new Error("Failed to connect to the script. Check CORS/Deployment permissions.");
    }
    throw error;
  }
}

