### Important Checklist for your Google Apps Script:

1.  **Deployment Settings**:
    *   Click **Deploy** -> **New Deployment**.
    *   Select **Web App**.
    *   Execute as: **Me** (Your email).
    *   Who has access: **Anyone** (This is the most critical setting).
2.  **Code Structure**: Your `.gs` script must handle `doGet` and `doPost` like this:
    ```javascript
    function doGet(e) {
      var action = e.parameter.action;
      // ... handle search or admin
      return ContentService.createTextOutput(JSON.stringify(result))
        .setMimeType(ContentService.MimeType.JSON);
    }

    function doPost(e) {
      var data = JSON.parse(e.postData.contents);
      // ... handle requestUpdate or approve
      return ContentService.createTextOutput(JSON.stringify({status: "success"}))
        .setMimeType(ContentService.MimeType.JSON);
    }
    ```
3.  **New Versions**: Remember that if you change the `.gs` code, you **must** create a "New Deployment" (or edit the existing deployment and select "New Version") for the changes to take effect at that URL.

To ensure the system works perfectly with the frontend I've built, here is the **complete Google Apps Script code**. 

You should copy this into your Google Apps Script editor (script.google.com), save it, and **Deploy as a Web App** (Set "Execute as: Me" and "Who has access: Anyone").

### The Google Sheets Setup
Your sheet should have these headers in the first row (Columns A to J):
1. **A:** StudentID
2. **B:** EnglishName
3. **C:** ArabicName
4. **D:** Grade
5. **E:** Class
6. **F:** Shirt
7. **G:** Trousers
8. **H:** Jacket
9. **I:** Notes
10. **J:** RequestStatus

---

### Google Apps Script Code (`Code.gs`)

```javascript
// CONFIGURATION
const ADMIN_PASSWORD = "KTS_ADMIN_2024"; // Change this to your desired admin password
const SHEET_NAME = "Sheet1"; // Change if your sheet tab has a different name

/**
 * Handles GET requests: Search and Admin fetching
 */
function doGet(e) {
  const action = e.parameter.action;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();
  const headers = data[0];

  // 1. ACTION: SEARCH STUDENT
  if (action === "search") {
    const studentId = e.parameter.studentId;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0].toString().trim() === studentId.trim()) {
        return jsonResponse({
          studentId: data[i][0],
          englishName: data[i][1],
          arabicName: data[i][2],
          grade: data[i][3],
          class: data[i][4],
          status: "found"
        });
      }
    }
    return jsonResponse({ status: "not_found" });
  }

  // 2. ACTION: ADMIN FETCH
  if (action === "admin") {
    const password = e.parameter.password;
    if (password !== ADMIN_PASSWORD) {
      return jsonResponse({ status: "error", message: "Invalid password" });
    }

    const pendingRequests = [];
    for (let i = 1; i < data.length; i++) {
      // Column J (index 9) is RequestStatus
      if (data[i][9] === "Pending") {
        pendingRequests.push({
          row: i + 1,
          studentId: data[i][0],
          englishName: data[i][1],
          grade: data[i][3],
          class: data[i][4],
          shirt: data[i][5],
          trousers: data[i][6],
          jacket: data[i][7],
          notes: data[i][8],
          requestStatus: data[i][9]
        });
      }
    }
    return jsonResponse(pendingRequests);
  }

  return jsonResponse({ status: "error", message: "Invalid action" });
}

/**
 * Handles POST requests: Submit Request and Approve
 */
function doPost(e) {
  try {
    const contents = JSON.parse(e.postData.contents);
    const action = contents.action;
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(SHEET_NAME);

    // 1. ACTION: REQUEST UPDATE (STUDENT SUBMISSION)
    if (action === "requestUpdate") {
      const studentId = contents.studentId;
      const data = sheet.getDataRange().getValues();

      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().trim() === studentId.trim()) {
          // Check for duplicate (if status is already Pending or Approved)
          if (data[i][9] === "Pending" || data[i][9] === "Approved") {
            return jsonResponse({ status: "duplicate", message: "Request already exists" });
          }

          // Update columns F, G, H, I, J (indices 5, 6, 7, 8, 9)
          const row = i + 1;
          sheet.getRange(row, 6).setValue(contents.shirt);
          sheet.getRange(row, 7).setValue(contents.trousers);
          sheet.getRange(row, 8).setValue(contents.jacket);
          sheet.getRange(row, 9).setValue(contents.notes);
          sheet.getRange(row, 10).setValue("Pending");

          return jsonResponse({ status: "success" });
        }
      }
      return jsonResponse({ status: "error", message: "Student not found in database" });
    }

    // 2. ACTION: APPROVE (ADMIN)
    if (action === "approve") {
      if (contents.password !== ADMIN_PASSWORD) {
        return jsonResponse({ status: "error", message: "Unauthorized" });
      }

      // Update Column J (index 10) for specific row
      sheet.getRange(contents.row, 10).setValue("Approved");
      return jsonResponse({ status: "success" });
    }

  } catch (err) {
    return jsonResponse({ status: "error", message: err.toString() });
  }
}

/**
 * Helper to return JSON with correct CORS headers
 */
function jsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### Instructions for Deployment:
1. Open your **Google Sheet**.
2. Go to **Extensions** > **Apps Script**.
3. Paste the code above into the editor.
4. Click the **Save** icon.
5. Click **Deploy** > **New Deployment**.
6. Select **Web App**.
7. **Description**: "KTS Uniform System V1"
8. **Execute as**: `Me`
9. **Who has access**: `Anyone` (This is critical).
10. Click **Deploy**, authorize the permissions, and copy the **Web App URL**.
11. Paste that URL into the `constants.ts` file in your project.

### Why this fixes your errors:
*   **CORS Fix**: It uses `ContentService.createTextOutput` with JSON MimeType, which Google uses to handle cross-origin requests.
*   **Redirect handling**: The script correctly returns data in a format the browser can read after following Google's internal redirects.
*   **Preflight Handling**: By expecting `text/plain` from the frontend (which we set up in the last step), the browser won't block the request for missing "OPTIONS" support.

