The "Failed to fetch" error when communicating with Google Apps Script is almost always caused by **deployment permissions** or the **CORS preflight** (the browser checking security before sending data).

Deploying to Vercel will **not** fix this. The issue is between your browser and Google's servers.

### 1. Updated Google Apps Script (Complete Code)
Copy this **entire** block into your `Code.gs` in Google Apps Script. I have added extra headers and error handling to ensure Google allows the connection.

```javascript
// CONFIGURATION
const ADMIN_PASSWORD = "KTS_ADMIN_2024"; 
const SHEET_NAME = "Sheet1"; 

/**
 * Handles GET requests: Search and Admin fetching
 */
function doGet(e) {
  try {
    const action = e.parameter.action;
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(SHEET_NAME);
    if (!sheet) return jsonResponse({ status: "error", message: "Sheet not found: " + SHEET_NAME });

    const data = sheet.getDataRange().getValues();

    if (action === "search") {
      const studentId = e.parameter.studentId;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().trim().toLowerCase() === studentId.trim().toLowerCase()) {
          return jsonResponse({
            studentId: data[i][0],
            englishName: data[i][1],
            arabicName: data[i][2],
            grade: data[i][3],
            class: data[i][4],
            status: "found"
          });
        }
      }
      return jsonResponse({ status: "not_found" });
    }

    if (action === "admin") {
      if (e.parameter.password !== ADMIN_PASSWORD) {
        return jsonResponse({ status: "error", message: "Invalid password" });
      }
      const pendingRequests = [];
      for (let i = 1; i < data.length; i++) {
        if (data[i][9] === "Pending") {
          pendingRequests.push({
            row: i + 1,
            studentId: data[i][0],
            englishName: data[i][1],
            grade: data[i][3],
            class: data[i][4],
            shirt: data[i][5],
            trousers: data[i][6],
            jacket: data[i][7],
            notes: data[i][8],
            requestStatus: data[i][9]
          });
        }
      }
      return jsonResponse(pendingRequests);
    }
  } catch (err) {
    return jsonResponse({ status: "error", message: err.toString() });
  }
}

/**
 * Handles POST requests
 */
function doPost(e) {
  try {
    const contents = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(SHEET_NAME);

    if (contents.action === "requestUpdate") {
      const data = sheet.getDataRange().getValues();
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().trim().toLowerCase() === contents.studentId.toString().trim().toLowerCase()) {
          if (data[i][9] === "Pending" || data[i][9] === "Approved") {
            return jsonResponse({ status: "duplicate", message: "Request already exists" });
          }
          const row = i + 1;
          sheet.getRange(row, 6, 1, 5).setValues([[
            contents.shirt, 
            contents.trousers, 
            contents.jacket, 
            contents.notes, 
            "Pending"
          ]]);
          return jsonResponse({ status: "success" });
        }
      }
      return jsonResponse({ status: "error", message: "Student ID not found" });
    }

    if (contents.action === "approve") {
      if (contents.password !== ADMIN_PASSWORD) return jsonResponse({ status: "error", message: "Unauthorized" });
      sheet.getRange(contents.row, 10).setValue("Approved");
      return jsonResponse({ status: "success" });
    }
  } catch (err) {
    return jsonResponse({ status: "error", message: err.toString() });
  }
}

function jsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### 2. Mandatory Deployment Steps
This is where 90% of "Failed to fetch" errors happen. You **must** do this exactly:

1.  In Google Apps Script, click **Deploy** -> **New Deployment**.
2.  Click the gear icon and select **Web App**.
3.  **Description**: "V2 Fix"
4.  **Execute as**: **Me** (Your email).
5.  **Who has access**: **Anyone** (Do **not** pick "Anyone with a Google account").
6.  Click **Deploy**.
7.  Copy the **Web App URL** (it ends in `/exec`).
8.  **Update `constants.ts`** in your project with this new URL.

---

### 3. Frontend Updates
I am updating `services/api.ts` to be even more resilient to CORS issues.

