import { StudentInfo, AdminRequestRow, UniformRequest } from '../types';
import { API_BASE_URL } from '../constants';

/**
 * To prevent "Failed to fetch" (CORS Errors) with Google Apps Script:
 * 1. GET requests are usually fine.
 * 2. POST requests must use Content-Type 'text/plain' to avoid an OPTIONS preflight.
 * 3. The deployment MUST be set to "Anyone".
 */
async function safeFetch(url: string, options: RequestInit = {}) {
  try {
    const fetchOptions: RequestInit = {
      method: options.method || 'GET',
      mode: 'cors',
      credentials: 'omit',
      redirect: 'follow',
      ...options,
    };

    // If POST, we MUST use a "Simple Request" format
    if (fetchOptions.method === 'POST') {
      // We don't even set headers here to stay as simple as possible
      // Google Apps Script will receive the body as a plain string
      fetchOptions.headers = {}; 
    }

    const response = await fetch(url, fetchOptions);

    if (!response.ok) {
      throw new Error(`HTTP Error: ${response.status}`);
    }

    const text = await response.text();

    try {
      return JSON.parse(text);
    } catch (e) {
      if (text.includes('<!DOCTYPE html>')) {
        throw new Error("The script returned HTML instead of JSON. This usually means the 'Who has access' setting is not set to 'Anyone' in your Google Apps Script deployment.");
      }
      throw new Error("Invalid response format from server.");
    }
  } catch (error: any) {
    console.error("Connection Error:", error);
    if (error.message === 'Failed to fetch') {
      throw new Error("Could not connect to the school database. Please check your internet or ensure the Google Script is deployed for 'Anyone'.");
    }
    throw error;
  }
}

