export default NotificationModal;

import React, { useState, useEffect } from 'react';
import { fetchAdminRequests, approveRequest, getMessage, updateMessage } from '../services/api';
import { AdminRequestRow, AdminTab, AppMessage } from '../types';
import { 
  Lock, ShieldCheck, UserCheck, Search, Loader2, 
  AlertCircle, RefreshCw, LogOut, MessageSquare, 
  LayoutList, Save, CheckCircle
} from 'lucide-react';
import { PRIMARY_BLUE } from '../constants';

const AdminPortal: React.FC = () => {
  const [password, setPassword] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [activeTab, setActiveTab] = useState<AdminTab>(AdminTab.REQUESTS);
  const [isLoading, setIsLoading] = useState(false);
  const [requests, setRequests] = useState<AdminRequestRow[]>([]);
  const [schoolMessage, setSchoolMessage] = useState<AppMessage>({ english: '', arabic: '' });
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [approvingRow, setApprovingRow] = useState<number | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      const data = await fetchAdminRequests(password);
      setRequests(data);
      const msg = await getMessage();
      setSchoolMessage(msg);
      setIsLoggedIn(true);
    } catch (err: any) {
      setError(err.message || 'Login failed.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleApprove = async (row: number) => {
    setApprovingRow(row);
    try {
      const success = await approveRequest(row, password);
      if (success) {
        setRequests(prev => prev.filter(r => r.row !== row));
      } else {
        setError('Failed to approve request.');
      }
    } catch (err) {
      setError('An error occurred.');
    } finally {
      setApprovingRow(null);
    }
  };

  const handleSaveMessage = async () => {
    setIsLoading(true);
    setError(null);
    setSuccess(null);
    try {
      const result = await updateMessage(schoolMessage, password);
      if (result) {
        setSuccess('Message updated successfully!');
        setTimeout(() => setSuccess(null), 3000);
      } else {
        setError('Failed to update message.');
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const refreshData = async () => {
    setIsLoading(true);
    try {
      const data = await fetchAdminRequests(password);
      setRequests(data);
    } catch (err) {
      setError('Refresh failed.');
    } finally {
      setIsLoading(false);
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="max-w-md mx-auto py-12 animate-in fade-in slide-in-from-top-4 duration-500">
        <div className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100">
          <div className="flex justify-center mb-6">
            <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center">
              <Lock className="h-8 w-8 text-blue-600" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-gray-900 text-center mb-2">Admin Portal</h2>
          <p className="text-gray-500 text-center mb-8">Access restricted to school staff.</p>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <input
                type="password"
                className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-center tracking-widest"
                placeholder="Enter Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
            </div>
            {error && (
              <div className="p-3 bg-red-50 border border-red-100 rounded-lg text-red-600 text-sm flex items-center gap-2">
                <AlertCircle className="h-4 w-4" />
                {error}
              </div>
            )}
            <button
              type="submit"
              disabled={isLoading}
              className="w-full py-4 rounded-xl font-bold text-white transition-all transform hover:scale-[1.02] active:scale-[0.98] flex items-center justify-center gap-2"
              style={{ backgroundColor: PRIMARY_BLUE }}
            >
              {isLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : "Access System"}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Admin Dashboard</h2>
          <p className="text-gray-500">Manage uniform requests and school announcements.</p>
        </div>
        <div className="flex items-center gap-2">
            <button 
                onClick={() => setIsLoggedIn(false)}
                className="p-3 rounded-xl bg-red-50 border border-red-100 hover:bg-red-100 transition-colors text-red-600 flex items-center gap-2 font-medium"
            >
                <LogOut className="h-5 w-5" />
                Logout
            </button>
        </div>
      </div>

      {/* Admin Tabs */}
      <div className="bg-white p-1 rounded-2xl shadow-sm border border-gray-100 flex gap-1">
        <button
          onClick={() => setActiveTab(AdminTab.REQUESTS)}
          className={`flex-1 flex items-center justify-center gap-2 py-3 px-4 rounded-xl font-semibold transition-all ${
            activeTab === AdminTab.REQUESTS 
            ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' 
            : 'text-gray-500 hover:bg-gray-50'
          }`}
        >
          <LayoutList className="h-4 w-4" />
          Pending Requests ({requests.length})
        </button>
        <button
          onClick={() => setActiveTab(AdminTab.MESSAGE)}
          className={`flex-1 flex items-center justify-center gap-2 py-3 px-4 rounded-xl font-semibold transition-all ${
            activeTab === AdminTab.MESSAGE 
            ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' 
            : 'text-gray-500 hover:bg-gray-50'
          }`}
        >
          <MessageSquare className="h-4 w-4" />
          Message Settings
        </button>
      </div>

      {activeTab === AdminTab.REQUESTS ? (
        <>
          <div className="flex justify-end">
            <button 
                onClick={refreshData}
                className="flex items-center gap-2 px-4 py-2 rounded-xl bg-white border border-gray-200 hover:bg-gray-50 transition-colors text-gray-600 text-sm font-semibold"
            >
                <RefreshCw className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
                Sync Data
            </button>
          </div>
          {requests.length === 0 ? (
            <div className="bg-white rounded-2xl shadow-soft p-20 border border-gray-100 text-center">
                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <UserCheck className="h-8 w-8 text-gray-300" />
                </div>
                <h3 className="text-lg font-semibold text-gray-900">All clear!</h3>
                <p className="text-gray-500">No pending requests at this moment.</p>
            </div>
          ) : (
            <div className="bg-white rounded-2xl shadow-soft border border-gray-100 overflow-hidden overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[800px]">
                <thead>
                  <tr className="bg-gray-50/50 border-b border-gray-100">
                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Student</th>
                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Group</th>
                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Sizes</th>
                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Notes</th>
                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider text-right">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {requests.map((req) => (
                    <tr key={req.row} className="hover:bg-blue-50/20 transition-colors">
                      <td className="px-6 py-5">
                        <div className="font-semibold text-gray-900">{req.englishName}</div>
                        <div className="text-xs text-gray-400">{req.studentId}</div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="text-sm font-medium text-gray-700">{req.grade}</div>
                        <div className="text-xs text-gray-400">{req.className}</div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex gap-1">
                          <span className="px-2 py-0.5 rounded-md text-[10px] font-bold bg-blue-100 text-blue-800">S:{req.shirt}</span>
                          <span className="px-2 py-0.5 rounded-md text-[10px] font-bold bg-indigo-100 text-indigo-800">T:{req.trousers}</span>
                          <span className="px-2 py-0.5 rounded-md text-[10px] font-bold bg-purple-100 text-purple-800">J:{req.jacket}</span>
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="text-sm text-gray-500 max-w-[150px] truncate" title={req.notes}>
                            {req.notes || <span className="text-gray-300 italic">None</span>}
                        </div>
                      </td>
                      <td className="px-6 py-5 text-right">
                        <button
                          onClick={() => handleApprove(req.row)}
                          disabled={approvingRow === req.row}
                          className="px-4 py-2 bg-green-600 hover:bg-green-700 disabled:opacity-50 text-white rounded-lg text-sm font-bold transition-all flex items-center justify-center gap-2 ml-auto"
                        >
                          {approvingRow === req.row ? <Loader2 className="h-4 w-4 animate-spin" /> : "Approve"}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      ) : (
        <div className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100 space-y-8 animate-in slide-in-from-bottom-4 duration-300">
          <div className="flex items-center gap-3 border-b border-gray-100 pb-4">
            <MessageSquare className="h-6 w-6 text-blue-600" />
            <h3 className="text-xl font-bold text-gray-900">Parent Notification Message</h3>
          </div>

          {success && (
            <div className="p-4 bg-green-50 border border-green-100 rounded-xl flex items-center gap-3 text-green-700 font-medium animate-in fade-in slide-in-from-top-2">
              <CheckCircle className="h-5 w-5" />
              {success}
            </div>
          )}

          {error && (
            <div className="p-4 bg-red-50 border border-red-100 rounded-xl flex items-center gap-3 text-red-700 font-medium">
              <AlertCircle className="h-5 w-5" />
              {error}
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-3">
              <label className="block text-sm font-bold text-gray-700 uppercase tracking-wider">English Message</label>
              <textarea
                value={schoolMessage.english}
                onChange={(e) => setSchoolMessage(prev => ({ ...prev, english: e.target.value }))}
                className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 transition-all h-48 resize-none text-gray-700"
                placeholder="Write message for parents in English..."
              />
            </div>
            <div className="space-y-3">
              <label className="block text-sm font-bold text-gray-700 uppercase tracking-wider text-right">Arabic Message | الرسالة بالعربية</label>
              <textarea
                value={schoolMessage.arabic}
                onChange={(e) => setSchoolMessage(prev => ({ ...prev, arabic: e.target.value }))}
                className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 transition-all h-48 resize-none text-gray-700 font-arabic text-lg text-right"
                dir="rtl"
                placeholder="اكتب الرسالة لأولياء الأمور باللغة العربية..."
              />
            </div>
          </div>

          <div className="flex justify-center pt-4">
            <button
              onClick={handleSaveMessage}
              disabled={isLoading}
              className="px-12 py-4 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white rounded-xl font-bold transition-all shadow-xl shadow-blue-600/20 flex items-center gap-2"
            >
              {isLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : <><Save className="h-5 w-5" /> Update Message</>}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPortal;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import StudentSearch from './components/StudentSearch';
import RequestForm from './components/RequestForm';
import AdminPortal from './components/AdminPortal';
import NotificationModal from './components/NotificationModal';
import { searchStudent, submitRequest, getMessage } from './services/api';
import { StudentInfo, UniformRequest, AppMode, AppMessage } from './types';
import { Shield, User, AlertCircle, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.STUDENT);
  const [currentStudent, setCurrentStudent] = useState<StudentInfo | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'duplicate' | 'error'>('idle');
  const [error, setError] = useState<string | null>(null);

  // Notification State
  const [showNotification, setShowNotification] = useState(false);
  const [schoolMessage, setSchoolMessage] = useState<AppMessage>({ english: '', arabic: '' });

  useEffect(() => {
    const fetchInitialData = async () => {
      try {
        const msg = await getMessage();
        setSchoolMessage(msg);
        if (msg.english || msg.arabic) {
          setShowNotification(true);
        }
      } catch (err) {
        console.error("Failed to fetch announcement", err);
      }
    };
    fetchInitialData();
  }, []);

  const handleSearch = async (id: string) => {
    setIsLoading(true);
    setError(null);
    setCurrentStudent(null);
    setSubmitStatus('idle');
    try {
      const student = await searchStudent(id);
      if (student) {
        setCurrentStudent(student);
      } else {
        setError("Student ID not found. Please verify and try again.");
      }
    } catch (err: any) {
      setError(err.message || "Connection error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmitRequest = async (request: UniformRequest) => {
    if (!currentStudent) return;
    setIsLoading(true);
    setError(null);
    try {
      const result = await submitRequest(currentStudent, request);
      if (result.success) {
        setSubmitStatus('success');
      } else if (result.message?.toLowerCase().includes('duplicate')) {
        setSubmitStatus('duplicate');
      } else {
        setSubmitStatus('error');
        setError(result.message || "Submission failed.");
      }
    } catch (err: any) {
      setSubmitStatus('error');
      setError(err.message || "Failed to submit.");
    } finally {
      setIsLoading(false);
    }
  };

  const resetError = () => {
    setError(null);
    setSubmitStatus('idle');
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#F9FAFB]">
      <Header />

      {showNotification && (
        <NotificationModal 
          message={schoolMessage} 
          onClose={() => setShowNotification(false)} 
        />
      )}

      {/* Tab Navigation */}
      <div className="bg-white border-b border-gray-100 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto flex justify-center">
          <nav className="flex gap-4 md:gap-8">
            <button
              onClick={() => {
                setMode(AppMode.STUDENT);
                resetError();
              }}
              className={`flex items-center gap-2 px-4 md:px-6 py-4 border-b-2 transition-all font-semibold text-sm md:text-base ${
                mode === AppMode.STUDENT 
                ? 'border-blue-600 text-blue-600' 
                : 'border-transparent text-gray-400 hover:text-gray-600'
              }`}
            >
              <User className="h-4 w-4" />
              Parent Portal
            </button>
            <button
              onClick={() => {
                setMode(AppMode.ADMIN);
                setCurrentStudent(null);
                resetError();
              }}
              className={`flex items-center gap-2 px-4 md:px-6 py-4 border-b-2 transition-all font-semibold text-sm md:text-base ${
                mode === AppMode.ADMIN 
                ? 'border-blue-600 text-blue-600' 
                : 'border-transparent text-gray-400 hover:text-gray-600'
              }`}
            >
              <Shield className="h-4 w-4" />
              Admin Portal
            </button>
          </nav>
        </div>
      </div>

      <main className="flex-grow container mx-auto px-4 py-8 md:py-12 max-w-4xl">
        {mode === AppMode.STUDENT ? (
          <div className="space-y-8">
            {!currentStudent && (
              <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                <StudentSearch onSearch={handleSearch} isLoading={isLoading} />

                {error && (
                  <div className="mt-6 p-6 bg-red-50 border border-red-100 rounded-2xl flex flex-col items-center gap-4 text-center animate-in shake duration-300">
                    <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center">
                      <AlertCircle className="h-6 w-6 text-red-600" />
                    </div>
                    <div>
                      <p className="font-bold text-red-900">Search Error</p>
                      <p className="text-sm text-red-700 mt-1 max-w-md">{error}</p>
                    </div>
                    <button 
                      onClick={resetError}
                      className="flex items-center gap-2 text-sm font-semibold text-red-600 hover:text-red-800 transition-colors"
                    >
                      <RefreshCw className="h-4 w-4" /> Try Again
                    </button>
                  </div>
                )}
              </div>
            )}

            {currentStudent && (
              <RequestForm 
                student={currentStudent} 
                onSubmit={handleSubmitRequest} 
                isSubmitting={isLoading}
                status={submitStatus}
              />
            )}
          </div>
        ) : (
          <AdminPortal />
        )}
      </main>

      <footer className="py-8 text-center text-gray-400 text-sm">
        <p>&copy; {new Date().getFullYear()} Knowledge Towers School. All Rights Reserved.</p>
      </footer>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          20%, 60% { transform: translateX(-5px); }
          40%, 80% { transform: translateX(5px); }
        }
        .animate-shake {
          animation: shake 0.4s ease-in-out;
        }
        .shadow-soft {
          box-shadow: 0 4px 20px -2px rgba(0, 0, 0, 0.05), 0 2px 10px -2px rgba(0, 0, 0, 0.02);
        }
        .font-arabic {
          font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }
      `}</style>
    </div>
  );
};

export default App;

