This is a sophisticated update that adds state management for requests, a global configuration for modification rules, and an inventory summary.

### Step 1: Updated Google Apps Script (Complete Code)
Replace your entire `Code.gs` with this code. It now handles the **Inventory Summary**, **Modification Toggles**, and **Existing Data** retrieval.

```javascript
// CONFIGURATION
const ADMIN_PASSWORD = "KTS_ADMIN_2024"; 
const SHEET_NAME = "Sheet1"; 
const MESSAGE_SHEET_NAME = "Message"; 

/**
 * GET Handler
 */
function doGet(e) {
  try {
    const action = e.parameter.action;
    const ss = SpreadsheetApp.getActiveSpreadsheet();

    // 1. GET MESSAGE & CONFIG
    if (action === "getMessage") {
      const msgSheet = ss.getSheetByName(MESSAGE_SHEET_NAME);
      if (!msgSheet) return jsonResponse({ english: "", arabic: "", modification: "enabled" });
      const data = msgSheet.getDataRange().getValues();
      return jsonResponse({ 
        english: data[1] ? data[1][0] : "", 
        arabic: data[1] ? data[1][1] : "",
        modification: data[1] ? (data[1][2] || "enabled") : "enabled"
      });
    }

    const sheet = ss.getSheetByName(SHEET_NAME);
    const data = sheet.getDataRange().getValues();

    // 2. SEARCH STUDENT (Now returns existing sizes)
    if (action === "search") {
      const studentId = e.parameter.studentId;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().trim().toLowerCase() === studentId.trim().toLowerCase()) {
          return jsonResponse({
            studentId: data[i][0],
            englishName: data[i][1],
            arabicName: data[i][2],
            grade: data[i][3],
            class: data[i][4],
            shirt: data[i][5] || "",
            trousers: data[i][6] || "",
            jacket: data[i][7] || "",
            status: data[i][9] || "",
            found: true
          });
        }
      }
      return jsonResponse({ found: false });
    }

    // 3. ADMIN: GET SUMMARY & REQUESTS
    if (action === "admin") {
      if (e.parameter.password !== ADMIN_PASSWORD) return jsonResponse({ status: "error", message: "Unauthorized" });

      if (e.parameter.subAction === "summary") {
        const summary = { shirt: {}, trousers: {}, jacket: {} };
        const sizes = ["S", "M", "L", "XL", "2XL"];
        sizes.forEach(s => { summary.shirt[s] = 0; summary.trousers[s] = 0; summary.jacket[s] = 0; });

        for (let i = 1; i < data.length; i++) {
          if (data[i][5]) summary.shirt[data[i][5]] = (summary.shirt[data[i][5]] || 0) + 1;
          if (data[i][6]) summary.trousers[data[i][6]] = (summary.trousers[data[i][6]] || 0) + 1;
          if (data[i][7]) summary.jacket[data[i][7]] = (summary.jacket[data[i][7]] || 0) + 1;
        }
        return jsonResponse(summary);
      }

      const pending = [];
      for (let i = 1; i < data.length; i++) {
        if (data[i][9] === "Pending" || data[i][9] === "ModificationRequested") {
          pending.push({
            row: i + 1,
            studentId: data[i][0], englishName: data[i][1], grade: data[i][3], class: data[i][4],
            shirt: data[i][5], trousers: data[i][6], jacket: data[i][7], notes: data[i][8],
            requestStatus: data[i][9]
          });
        }
      }
      return jsonResponse(pending);
    }
  } catch (err) { return jsonResponse({ status: "error", message: err.toString() }); }
}

/**
 * POST Handler
