import { StudentInfo, AdminRequestRow, UniformRequest, AppMessage, SizeSummary } from '../types';
import { API_BASE_URL } from '../constants';

/**
 * Advanced Fetch wrapper to handle Google Apps Script's specific CORS requirements.
 * Google Apps Script triggers a 302 redirect and fails CORS if specific headers 
 * (like Content-Type: application/json) are used during a POST.
 */
async function safeFetch(url: string, options: RequestInit = {}) {
  try {
    const fetchOptions: RequestInit = {
      method: options.method || 'GET',
      mode: 'cors',
      credentials: 'omit',
      redirect: 'follow',
      ...options,
    };

    // For POST requests, we DO NOT set any headers to keep it as a "Simple Request".
    // This allows us to bypass the OPTIONS preflight that GAS doesn't handle well.
    if (fetchOptions.method === 'POST') {
      fetchOptions.headers = {}; 
    }

    const response = await fetch(url, fetchOptions);

    if (!response.ok) {
      throw new Error(`Server returned status ${response.status}`);
    }

    const text = await response.text();

    try {
      return JSON.parse(text);
    } catch (e) {
      // If we got HTML, it usually means Google is asking for a login or script is not shared properly.
      if (text.includes('<!DOCTYPE html>')) {
        throw new Error("Access denied. Please ensure your Google Script is deployed with 'Who has access' set to 'Anyone'.");
      }
      throw new Error("Invalid response format from server.");
    }
  } catch (error: any) {
    console.error("API Error:", error);
    if (error.message === 'Failed to fetch') {
      throw new Error("Connection failed. This is usually due to CORS. Ensure the script is deployed for 'Anyone'.");
    }
    throw error;
  }
}

export const getMessage = async (): Promise<AppMessage> => {
  const url = `${API_BASE_URL}?action=getMessage`;
  const data = await safeFetch(url);
  return {
    english: data?.english || "",
    arabic: data?.arabic || "",
    modification: data?.modification || "enabled"
  };
};

export const updateMessage = async (message: AppMessage, password: string): Promise<boolean> => {
  const payload = { action: "updateMessage", password, ...message };
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify(payload) 
  });
  return !!(data && data.status === 'success');
};

export const searchStudent = async (studentId: string): Promise<StudentInfo | null> => {
  const url = `${API_BASE_URL}?action=search&studentId=${encodeURIComponent(studentId.trim())}`;
  const data = await safeFetch(url);
  if (data && data.found) {
    return {
      studentId: data.studentId.toString(),
      englishName: data.englishName,
      arabicName: data.arabicName,
      grade: data.grade,
      className: data.class,
      existingShirt: data.shirt,
      existingTrousers: data.trousers,
      existingJacket: data.jacket,
      status: data.status
    };
  }
  return null;
};

export const requestModification = async (studentId: string): Promise<boolean> => {
  const payload = { action: "requestModification", studentId };
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify(payload) 
  });
  return !!(data && data.status === 'success');
};

export const fetchSummary = async (password: string): Promise<SizeSummary> => {
  const url = `${API_BASE_URL}?action=admin&subAction=summary&password=${encodeURIComponent(password)}`;
  return await safeFetch(url);
};

export const allowEdit = async (row: number, password: string): Promise<boolean> => {
  const payload = { action: "allowEdit", row, password };
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify(payload) 
  });
  return !!(data && data.status === 'success');
};

export const submitRequest = async (student: StudentInfo, request: UniformRequest): Promise<{ success: boolean; message?: string }> => {
  const payload = { 
    action: "requestUpdate", 
    studentId: student.studentId, 
    ...request 
  };
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify(payload) 
  });
  return { success: data && data.status === 'success', message: data?.message };
};

export const fetchAdminRequests = async (password: string): Promise<AdminRequestRow[]> => {
  const url = `${API_BASE_URL}?action=admin&password=${encodeURIComponent(password)}`;
  const data = await safeFetch(url);
  return Array.isArray(data) ? data.map((item: any) => ({ ...item, className: item.class })) : [];
};

export const approveRequest = async (row: number, password: string): Promise<boolean> => {
  const payload = { action: "approve", row, password };
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify(payload) 
  });
  return !!(data && data.status === 'success');
};

