import { StudentInfo, AdminRequestRow, UniformRequest, AppMessage, SizeSummary } from '../types';
import { API_BASE_URL } from '../constants';

/**
 * Advanced Fetch wrapper to handle Google Apps Script's specific CORS requirements.
 * Google Apps Script triggers a CORS error if custom headers (like Content-Type: application/json) 
 * are used because it doesn't support the OPTIONS preflight correctly for all environments.
 */
async function safeFetch(url: string, options: RequestInit = {}) {
  try {
    const fetchOptions: RequestInit = {
      method: options.method || 'GET',
      mode: 'cors',
      credentials: 'omit',
      redirect: 'follow',
      ...options,
    };

    // CRITICAL: For POST requests, we MUST NOT set custom headers.
    // By sending a string body with no Content-Type header, the browser defaults to 'text/plain'.
    // This is a "Simple Request" that bypasses CORS preflight (OPTIONS) checks.
    if (fetchOptions.method === 'POST') {
      delete (fetchOptions as any).headers;
    }

    const response = await fetch(url, fetchOptions);

    if (!response.ok) {
      throw new Error(`HTTP Error: ${response.status}`);
    }

    const text = await response.text();

    try {
      return JSON.parse(text);
    } catch (e) {
      // If the response is HTML, it means Google is redirecting to a login page.
      // This only happens if 'Who has access' is NOT set to 'Anyone' in deployment.
      if (text.includes('<!DOCTYPE html>')) {
        throw new Error("Backend Access Denied. You MUST deploy the Google Script with 'Who has access: Anyone'.");
      }
      throw new Error("Malformed data received from server.");
    }
  } catch (error: any) {
    console.error("Detailed Fetch Error:", error);
    if (error.message === 'Failed to fetch') {
      throw new Error("Network connection blocked by CORS. Ensure your Google Script is deployed with 'Who has access: Anyone'.");
    }
    throw error;
  }
