### 2. Complete Google Apps Script (Code.gs)
Ensure your `Code.gs` in the Google Spreadsheet editor is exactly as follows:

```javascript
/**
 * KTS UNIFORM SYSTEM - BACKEND ENGINE
 */
const ADMIN_PASSWORD = "KTS_ADMIN_2024"; 
const SHEET_NAME = "Sheet1"; 
const MESSAGE_SHEET_NAME = "Message"; 

function doGet(e) {
  try {
    const action = e.parameter.action;
    const ss = SpreadsheetApp.getActiveSpreadsheet();

    if (action === "getMessage") {
      let msgSheet = ss.getSheetByName(MESSAGE_SHEET_NAME);
      if (!msgSheet) return jsonResponse({ english: "", arabic: "", modification: "enabled" });
      const data = msgSheet.getDataRange().getValues();
      return jsonResponse({ 
        english: data[1] ? (data[1][0] || "") : "", 
        arabic: data[1] ? (data[1][1] || "") : "",
        modification: data[1] ? (data[1][2] || "enabled") : "enabled"
      });
    }

    const sheet = ss.getSheetByName(SHEET_NAME);
    const data = sheet.getDataRange().getValues();

    if (action === "search") {
      const studentId = e.parameter.studentId;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().trim().toLowerCase() === studentId.trim().toLowerCase()) {
          return jsonResponse({
            studentId: data[i][0], englishName: data[i][1], arabicName: data[i][2],
            grade: data[i][3], class: data[i][4], shirt: data[i][5] || "",
            trousers: data[i][6] || "", jacket: data[i][7] || "", status: data[i][9] || "",
            found: true
          });
        }
      }
      return jsonResponse({ found: false });
    }

    if (action === "admin") {
      if (e.parameter.password !== ADMIN_PASSWORD) return jsonResponse({ status: "error" });
      if (e.parameter.subAction === "summary") {
        const summary = { shirt: {}, trousers: {}, jacket: {} };
        const sizes = ["S", "M", "L", "XL", "2XL"];
        sizes.forEach(s => { summary.shirt[s] = 0; summary.trousers[s] = 0; summary.jacket[s] = 0; });
        for (let i = 1; i < data.length; i++) {
          const s = data[i][5]; if (s && summary.shirt[s] !== undefined) summary.shirt[s]++;
          const t = data[i][6]; if (t && summary.trousers[t] !== undefined) summary.trousers[t]++;
          const j = data[i][7]; if (j && summary.jacket[j] !== undefined) summary.jacket[j]++;
        }
        return jsonResponse(summary);
      }
      const pending = [];
      for (let i = 1; i < data.length; i++) {
        const status = data[i][9];
        if (status === "Pending" || status === "ModificationRequested") {
          pending.push({
            row: i + 1, studentId: data[i][0], englishName: data[i][1], grade: data[i][3], class: data[i][4],
            shirt: data[i][5], trousers: data[i][6], jacket: data[i][7], notes: data[i][8], requestStatus: status
          });
        }
      }
      return jsonResponse(pending);
    }
  } catch (err) { return jsonResponse({ status: "error", message: err.toString() }); }
}

function doPost(e) {
  try {
    const contents = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(SHEET_NAME);

    if (contents.action === "updateMessage") {
      if (contents.password !== ADMIN_PASSWORD) return jsonResponse({ status: "error" });
      let msgSheet = ss.getSheetByName(MESSAGE_SHEET_NAME) || ss.insertSheet(MESSAGE_SHEET_NAME);
      if (msgSheet.getLastRow() === 0) msgSheet.appendRow(["E", "A", "M"]);
      msgSheet.getRange(2, 1, 1, 3).setValues([[contents.english, contents.arabic, contents.modification]]);
      return jsonResponse({ status: "success" });
    }

    if (contents.action === "requestUpdate") {
      const data = sheet.getDataRange().getValues();
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().trim().toLowerCase() === contents.studentId.toString().trim().toLowerCase()) {
          sheet.getRange(i + 1, 6, 1, 5).setValues([[contents.shirt, contents.trousers, contents.jacket, contents.notes, "Pending"]]);
          return jsonResponse({ status: "success" });
        }
      }
    }

    if (contents.action === "requestModification") {
      const data = sheet.getDataRange().getValues();
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().trim().toLowerCase() === contents.studentId.toString().trim().toLowerCase()) {
          sheet.getRange(i + 1, 10).setValue("ModificationRequested");
          return jsonResponse({ status: "success" });
        }
      }
    }

    if (contents.action === "approve") {
      sheet.getRange(contents.row, 10).setValue("Approved");
      return jsonResponse({ status: "success" });
    }

    if (contents.action === "allowEdit") {
      sheet.getRange(contents.row, 10).setValue("Modifiable");
      return jsonResponse({ status: "success" });
    }
  } catch (err) { return jsonResponse({ status: "error", message: err.toString() }); }
}

function jsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
}
```

