/**
 * Robust fetch wrapper for Google Apps Script.
 * Avoids CORS preflight by using simple requests (no custom headers).
 */
async function safeFetch(url: string, options: RequestInit = {}) {
  try {
    const isPost = options.method === 'POST';

    const fetchOptions: RequestInit = {
      method: options.method || 'GET',
      mode: 'cors',
      credentials: 'omit',
      redirect: 'follow',
      body: options.body,
    };

    // IMPORTANT: To avoid CORS preflight (OPTIONS), we must NOT send any custom headers.
    // This includes 'Content-Type: application/json'. Google Apps Script handles this fine.
    const response = await fetch(url, fetchOptions);

    if (!response.ok) {
      throw new Error(`Server returned ${response.status}`);
    }

    const text = await response.text();

    try {
      const json = JSON.parse(text);
      if (json.error) throw new Error(json.error);
      return json;
    } catch (e) {
      if (text.includes('<!DOCTYPE html>')) {
        throw new Error("Access Denied: Ensure your Google Script is deployed as 'Anyone'.");
      }
      throw new Error("Invalid response from server.");
