const ADMIN_PASSWORD = "KTS_ADMIN_2024";

function doGet(e) {
  const action = e.parameter.action;
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  try {
    if (action === "getMessage") {
      let msgSheet = ss.getSheetByName("Message");
      if (!msgSheet) return jsonResponse({ english: "", arabic: "", modification: "enabled" });
      const data = msgSheet.getRange(2, 1, 1, 3).getValues()[0];
      return jsonResponse({ english: data[0] || "", arabic: data[1] || "", modification: data[2] || "enabled" });
    }

    const sheet = ss.getSheetByName("Sheet1");
    if (!sheet) return jsonResponse({ error: "Sheet1 not found" });
    const data = sheet.getDataRange().getValues();

    if (action === "search") {
      const id = (e.parameter.studentId || "").toLowerCase().trim();
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().toLowerCase().trim() === id) {
          return jsonResponse({
            found: true, studentId: data[i][0], englishName: data[i][1], arabicName: data[i][2],
            grade: data[i][3], class: data[i][4], shirt: data[i][5], trousers: data[i][6], 
            jacket: data[i][7], notes: data[i][8], status: data[i][9]
          });
        }
      }
      return jsonResponse({ found: false });
    }

    if (action === "admin") {
      if (e.parameter.password !== ADMIN_PASSWORD) return jsonResponse({ error: "Unauthorized" });

      if (e.parameter.subAction === "summary") {
        const summary = { shirt: {}, trousers: {}, jacket: {} };
        for (let i = 1; i < data.length; i++) {
          ['shirt', 'trousers', 'jacket'].forEach((type, idx) => {
            const size = data[i][5 + idx];
            if (size) summary[type][size] = (summary[type][size] || 0) + 1;
          });
        }
        return jsonResponse(summary);
      }

      const pending = [];
      for (let i = 1; i < data.length; i++) {
        const s = data[i][9];
        if (s === "Pending" || s === "ModificationRequested") {
          pending.push({
            row: i + 1, studentId: data[i][0], englishName: data[i][1], grade: data[i][3], class: data[i][4],
            shirt: data[i][5], trousers: data[i][6], jacket: data[i][7], notes: data[i][8], requestStatus: s
          });
        }
      }
      return jsonResponse(pending);
    }
    return jsonResponse({ error: "Unknown action" });
  } catch (f) { 
    return jsonResponse({ error: f.toString() }); 
  }
}

function doPost(e) {
  try {
    const contents = e.postData.contents;
    const p = JSON.parse(contents);
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName("Sheet1");

    if (p.action === "updateMessage") {
      if (p.password !== ADMIN_PASSWORD) return jsonResponse({ status: "error" });
      let mSheet = ss.getSheetByName("Message") || ss.insertSheet("Message");
      mSheet.getRange(1, 1, 1, 3).setValues([["English", "Arabic", "Mod"]]);
      mSheet.getRange(2, 1, 1, 3).setValues([[p.english, p.arabic, p.modification]]);
      return jsonResponse({ status: "success" });
    }

    const data = sheet.getDataRange().getValues();
    const findRow = (id) => {
      const searchId = id.toString().toLowerCase().trim();
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString().toLowerCase().trim() === searchId) return i + 1;
      }
      return -1;
    };

    if (p.action === "requestUpdate") {
      const row = findRow(p.studentId);
      if (row > 0) {
        sheet.getRange(row, 6, 1, 5).setValues([[p.shirt, p.trousers, p.jacket, p.notes, "Pending"]]);
        return jsonResponse({ status: "success" });
      }
    }

    if (p.action === "requestModification") {
      const row = findRow(p.studentId);
      if (row > 0) {
        sheet.getRange(row, 10).setValue("ModificationRequested");
        return jsonResponse({ status: "success" });
      }
    }

    if (p.action === "approve") {
      if (p.password === ADMIN_PASSWORD) {
        sheet.getRange(p.row, 10).setValue("Approved");
        return jsonResponse({ status: "success" });
      }
    }

    if (p.action === "allowEdit") {
      if (p.password === ADMIN_PASSWORD) {
        sheet.getRange(p.row, 10).setValue("Modifiable");
        return jsonResponse({ status: "success" });
      }
    }

    return jsonResponse({ status: "error", message: "Action failed or unauthorized" });
  } catch (f) { 
    return jsonResponse({ status: "error", message: f.toString() }); 
  }
}

function jsonResponse(obj) {
  return ContentService.createTextOutput(JSON.stringify(obj)).setMimeType(ContentService.MimeType.JSON);
