  }, []);

  const resetState = () => {
    setCurrentStudent(null);
    setSubmitStatus('idle');
    setError(null);
  };

  const handleSearch = async (id: string) => {
    setIsLoading(true);
    setError(null);
    setCurrentStudent(null);
    setSubmitStatus('idle');
    try {
      const student = await searchStudent(id);
      if (student) setCurrentStudent(student);
      else setError("Student ID not found. Please verify your ID.");
    } catch (err: any) { 
      setError(err.message || "A connection error occurred."); 
    } finally { 
      setIsLoading(false); 
    }
  };

  const handleSubmitRequest = async (request: UniformRequest) => {
    if (!currentStudent) return;
    setIsLoading(true);
    try {
      const result = await submitRequest(currentStudent, request);
      if (result.success) setSubmitStatus('success');
      else setSubmitStatus('error');
    } catch (err: any) { 
      setSubmitStatus('error'); 
    } finally { 
      setIsLoading(false); 
    }
  };

  const onModificationSuccess = (updatedStudent: StudentInfo) => {
    setCurrentStudent(updatedStudent);
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#F9FAFB]">
      <Header />
      {showNotification && <NotificationModal message={schoolMessage} onClose={() => setShowNotification(false)} />}
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-7xl mx-auto flex justify-center">
          <nav className="flex gap-4 md:gap-8">
            <button 
              onClick={() => { setMode(AppMode.STUDENT); resetState(); }} 
              className={`flex items-center gap-2 px-6 py-4 border-b-2 font-bold transition-all ${mode === AppMode.STUDENT ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-400'}`}
            >
              <User className="h-4 w-4" /> Parent Portal
            </button>
            <button 
              onClick={() => { setMode(AppMode.ADMIN); resetState(); }} 
              className={`flex items-center gap-2 px-6 py-4 border-b-2 font-bold transition-all ${mode === AppMode.ADMIN ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-400'}`}
            >
              <Shield className="h-4 w-4" /> Staff Portal
            </button>
          </nav>
        </div>
      </div>
      <main className="flex-grow container mx-auto px-4 py-8 max-w-4xl">
        {mode === AppMode.STUDENT ? (
          <div className="space-y-8">
            {!currentStudent && <StudentSearch onSearch={handleSearch} isLoading={isLoading} />}
            {error && !currentStudent && (
              <div className="p-4 bg-red-50 text-red-600 rounded-xl text-center font-bold border border-red-100 animate-in fade-in slide-in-from-top-2">
                {error}
              </div>
            )}
            {currentStudent && (
              <RequestForm 
                config={schoolMessage} 
                student={currentStudent} 
                onSubmit={handleSubmitRequest} 
                isSubmitting={isLoading} 
                status={submitStatus}
                onReset={resetState}
                onModificationSuccess={onModificationSuccess}
              />
            )}
          </div>
        ) : <AdminPortal />}
      </main>
      <footer className="py-8 text-center text-gray-400 text-sm">
        <p>&copy; {new Date().getFullYear()} Knowledge Towers School. All Rights Reserved.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudentInfo, UniformRequest, UniformSize, AppMessage } from '../types';
import { UNIFORM_SIZES, PRIMARY_BLUE } from '../constants';
import { User, ClipboardList, CheckCircle2, AlertCircle, Loader2, Edit3, Hourglass, RefreshCw } from 'lucide-react';
import { requestModification, searchStudent } from '../services/api';

interface RequestFormProps {
  student: StudentInfo;
  onSubmit: (request: UniformRequest) => Promise<void>;
  isSubmitting: boolean;
  status: 'idle' | 'success' | 'duplicate' | 'error';
  config: AppMessage;
  onReset: () => void;
  onModificationSuccess: (updated: StudentInfo) => void;
}

const RequestForm: React.FC<RequestFormProps> = ({ 
  student, onSubmit, isSubmitting, status, config, onReset, onModificationSuccess 
}) => {
  const [isModifying, setIsModifying] = useState(student.status === 'Modifiable' || !student.status);
  const [modReqLoading, setModReqLoading] = useState(false);
  const [modError, setModError] = useState<string | null>(null);

  const [form, setForm] = useState<UniformRequest>({
    shirt: (student.existingShirt as UniformSize) || '',
    trousers: (student.existingTrousers as UniformSize) || '',
    jacket: (student.existingJacket as UniformSize) || '',
    notes: ''
  });

  const handleModRequest = async () => {
    setModReqLoading(true);
    setModError(null);
    try {
      const ok = await requestModification(student.studentId);
      if (ok) {
        // Fetch updated student status from server instead of reloading
        const updated = await searchStudent(student.studentId);
        if (updated) {
          onModificationSuccess(updated);
        }
      } else {
        setModError("The request could not be completed. Please contact school support.");
      }
    } catch (err: any) {
      setModError(err.message || "Failed to contact server.");
    } finally {
      setModReqLoading(false);
    }
  };

  const handleRefresh = async () => {
    setModReqLoading(true);
    try {
      const updated = await searchStudent(student.studentId);
      if (updated) onModificationSuccess(updated);
    } finally {
      setModReqLoading(false);
    }
  };

  const hasExistingData = !!(student.existingShirt || student.existingTrousers || student.existingJacket);
  const isWaitState = config.modification === 'enabled' && student.status === 'ModificationRequested';
  const showReadOnly = hasExistingData && !isModifying && student.status !== 'Modifiable';

  if (status === 'success') {
    return (
      <div className="bg-white rounded-2xl shadow-soft p-12 border border-green-100 text-center animate-in fade-in zoom-in">
        <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle2 className="h-10 w-10 text-green-500" />
        </div>
        <h3 className="text-2xl font-bold text-gray-900 mb-2">Request Saved!</h3>
        <p className="text-gray-600 mb-8 max-w-md mx-auto">Your sizing has been submitted. You can check the status later using your Student ID.</p>
        <button 
          onClick={onReset} 
          className="px-8 py-3 bg-gray-100 text-gray-700 font-bold rounded-xl hover:bg-gray-200 transition-colors"
        >
          Return to Search
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-soft border border-gray-100 overflow-hidden">
        <div className="bg-blue-50/50 px-8 py-4 border-b border-blue-50 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <User className="h-5 w-5 text-blue-600" />
            <h3 className="font-semibold text-blue-900">Student Profile</h3>
          </div>
          {student.status && (
            <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
              student.status === 'Approved' ? 'bg-green-100 text-green-700' : 
              student.status === 'Pending' ? 'bg-blue-100 text-blue-700' : 
              student.status === 'Modifiable' ? 'bg-indigo-100 text-indigo-700' :
              'bg-amber-100 text-amber-700'
            }`}>
              {student.status === 'ModificationRequested' ? 'Status: Pending Review' : 
               student.status === 'Modifiable' ? 'Status: Ready to Edit' : `Status: ${student.status}`}
            </span>
          )}
        </div>
        <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">English Name</p><p className="text-lg font-bold text-gray-900">{student.englishName}</p></div>
          <div className="text-right"><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Arabic Name</p><p className="text-lg font-bold text-gray-900 font-arabic" dir="rtl">{student.arabicName}</p></div>
          <div><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Class Info</p><p className="text-gray-700 font-medium">{student.grade} - {student.className}</p></div>
          <div className="text-right"><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Student ID</p><p className="text-gray-700 font-medium">{student.studentId}</p></div>
        </div>
      </div>

      {isWaitState ? (
        <div className="bg-white rounded-2xl shadow-soft p-12 border border-amber-100 text-center space-y-4">
           <Hourglass className="h-12 w-12 text-amber-500 mx-auto animate-pulse" />
           <h3 className="text-xl font-bold text-gray-900">Modification Requested</h3>
           <p className="text-gray-600 max-w-md mx-auto font-medium leading-relaxed">
             We have received your request to change sizes. Our staff is currently reviewing it. Please check back in a few hours.
           </p>
           <div className="pt-4 flex flex-col items-center gap-3">
             <button 
                onClick={handleRefresh} 
                disabled={modReqLoading}
                className="flex items-center gap-2 px-6 py-2 bg-amber-50 text-amber-700 rounded-xl font-bold hover:bg-amber-100 transition-all border border-amber-200"
             >
               {modReqLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <><RefreshCw className="h-4 w-4" /> Check Status Now</>}
             </button>
             <button onClick={onReset} className="text-gray-400 text-sm font-semibold hover:text-gray-600 hover:underline">Back to Search</button>
           </div>
        </div>
      ) : showReadOnly ? (
        <div className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100 space-y-6">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
             <div>
               <h3 className="text-xl font-bold text-gray-900">Current Saved Sizes</h3>
               <p className="text-sm text-gray-500">Your information is already on file.</p>
             </div>
             <button 
                onClick={config.modification === 'disabled' ? () => setIsModifying(true) : handleModRequest}
                disabled={modReqLoading}
                className="flex items-center justify-center gap-2 px-6 py-2 bg-blue-50 text-blue-700 rounded-xl font-bold hover:bg-blue-100 transition-all border border-blue-100 disabled:opacity-50"
             >
               {modReqLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <><Edit3 className="h-4 w-4" /> {config.modification === 'disabled' ? 'Modify Sizes' : 'Request Modification'}</>}
             </button>
          </div>
          {modError && (
            <div className="p-4 bg-red-50 text-red-600 rounded-xl text-xs font-bold flex items-center gap-2">
              <AlertCircle className="h-4 w-4 shrink-0" /> {modError}
            </div>
          )}
          <div className="grid grid-cols-3 gap-4">
            <div className="p-4 bg-gray-50 rounded-xl text-center"><p className="text-[10px] text-gray-400 font-bold uppercase">Shirt</p><p className="text-2xl font-black text-gray-900">{student.existingShirt || '-'}</p></div>
            <div className="p-4 bg-gray-50 rounded-xl text-center"><p className="text-[10px] text-gray-400 font-bold uppercase">Trousers</p><p className="text-2xl font-black text-gray-900">{student.existingTrousers || '-'}</p></div>
            <div className="p-4 bg-gray-50 rounded-xl text-center"><p className="text-[10px] text-gray-400 font-bold uppercase">Jacket</p><p className="text-2xl font-black text-gray-900">{student.existingJacket || '-'}</p></div>
          </div>
          <div className="pt-2 text-center">
            <button onClick={onReset} className="text-gray-400 text-xs font-bold hover:text-gray-600">Search for another student</button>
          </div>
        </div>
      ) : (
        <form onSubmit={(e) => { e.preventDefault(); onSubmit(form); }} className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100 space-y-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <ClipboardList className="h-6 w-6 text-blue-600" />
              <h2 className="text-xl font-bold text-gray-900">Select Sizes</h2>
            </div>
            {hasExistingData && (
              <button type="button" onClick={() => setIsModifying(false)} className="text-sm text-gray-400 font-bold hover:text-gray-600">View Current</button>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {(['shirt', 'trousers', 'jacket'] as const).map((item) => (
              <div key={item} className="space-y-2">
                <label className="block text-xs font-bold text-gray-700 uppercase tracking-wider">{item}</label>
                <select 
                  value={form[item]} 
                  onChange={(e) => setForm(f => ({ ...f, [item]: e.target.value as UniformSize }))}
                  className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-gray-900"
                  required
                >
                  <option value="">Select Size</option>
                  {UNIFORM_SIZES.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            ))}
          </div>

          <div className="space-y-2">
            <label className="block text-xs font-bold text-gray-700 uppercase tracking-wider">Additional Notes</label>
            <textarea 
              placeholder="Any special requirements or fitting notes..."
              className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl h-32 outline-none focus:ring-2 focus:ring-blue-500"
              value={form.notes} onChange={(e) => setForm(f => ({ ...f, notes: e.target.value }))}
            />
          </div>

          <div className="flex flex-col gap-4">
            <button 
              type="submit" disabled={isSubmitting}
              style={{ backgroundColor: PRIMARY_BLUE }}
              className="w-full py-4 text-white font-bold rounded-xl shadow-lg shadow-blue-900/10 flex items-center justify-center gap-2 hover:opacity-90 transition-opacity disabled:opacity-50"
            >
              {isSubmitting ? <Loader2 className="h-5 w-5 animate-spin" /> : "Submit Uniform Request"}
            </button>
            <button 
              type="button" 
              onClick={onReset}
              className="w-full py-2 text-gray-400 font-bold text-sm hover:text-gray-600 transition-colors"
            >
              Cancel and Return to Search
            </button>
          </div>
        </form>
      )}
    </div>
  );
};

export default RequestForm;

import { StudentInfo, AdminRequestRow, UniformRequest, AppMessage, SizeSummary } from '../types';
import { API_BASE_URL } from '../constants';

/**
 * Robust fetch wrapper for Google Apps Script.
 * Avoids CORS preflight by using simple requests (no custom headers).
 */
async function safeFetch(url: string, options: RequestInit = {}) {
  try {
    const fetchOptions: RequestInit = {
      method: options.method || 'GET',
      mode: 'cors',
      credentials: 'omit',
      redirect: 'follow',
      body: options.body,
    };

    const response = await fetch(url, fetchOptions);

    if (!response.ok) {
      throw new Error(`Server connection failed with status ${response.status}`);
    }

    const text = await response.text();

    try {
      const json = JSON.parse(text);
      if (json.error) throw new Error(json.error);
      return json;
    } catch (e) {
      if (text.includes('<!DOCTYPE html>')) {
        throw new Error("Application configuration error: Backend access denied. Please contact school admin.");
      }
      throw new Error("Received an unexpected response format from the server.");
    }
  } catch (error: any) {
    console.error("API Communication Error:", error);
    throw error;
  }
}

export const getMessage = async (): Promise<AppMessage> => {
  try {
    const data = await safeFetch(`${API_BASE_URL}?action=getMessage`);
    return {
      english: data?.english || "",
      arabic: data?.arabic || "",
      modification: data?.modification || "enabled"
    };
  } catch (err) {
    return { english: "", arabic: "", modification: "enabled" };
  }
};

export const updateMessage = async (message: AppMessage, password: string): Promise<boolean> => {
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify({ action: "updateMessage", password, ...message }) 
  });
  return data?.status === 'success';
};

export const searchStudent = async (studentId: string): Promise<StudentInfo | null> => {
  if (!studentId) return null;
  const url = `${API_BASE_URL}?action=search&studentId=${encodeURIComponent(studentId.trim())}`;
  const data = await safeFetch(url);
  if (data && data.found) {
    return {
      studentId: data.studentId.toString(),
      englishName: data.englishName || "",
      arabicName: data.arabicName || "",
      grade: data.grade || "",
      className: data.class || "",
      existingShirt: data.shirt || "",
      existingTrousers: data.trousers || "",
      existingJacket: data.jacket || "",
      status: data.status || ""
    };
  }
  return null;
};

export const requestModification = async (studentId: string): Promise<boolean> => {
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify({ action: "requestModification", studentId }) 
  });
  return data?.status === 'success';
};

export const fetchSummary = async (password: string): Promise<SizeSummary> => {
  return await safeFetch(`${API_BASE_URL}?action=admin&subAction=summary&password=${encodeURIComponent(password)}`);
};

export const allowEdit = async (row: number, password: string): Promise<boolean> => {
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify({ action: "allowEdit", row, password }) 
  });
  return data?.status === 'success';
};

export const submitRequest = async (student: StudentInfo, request: UniformRequest): Promise<{ success: boolean; message?: string }> => {
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify({ action: "requestUpdate", studentId: student.studentId, ...request }) 
  });
  return { success: data?.status === 'success', message: data?.message };
};

export const fetchAdminRequests = async (password: string): Promise<AdminRequestRow[]> => {
  const data = await safeFetch(`${API_BASE_URL}?action=admin&password=${encodeURIComponent(password)}`);
  if (!Array.isArray(data)) return [];
  return data.map((item: any) => ({ ...item, className: item.class || "" }));
};

export const approveRequest = async (row: number, password: string): Promise<boolean> => {
  const data = await safeFetch(API_BASE_URL, { 
    method: 'POST', 
    body: JSON.stringify({ action: "approve", row, password }) 
  });
  return data?.status === 'success';
};

