  onModificationSuccess: (updated: StudentInfo) => void;
}

const RequestForm: React.FC<RequestFormProps> = ({ 
  student, onSubmit, isSubmitting, status, config, onReset, onModificationSuccess 
}) => {
  // A student can edit if:
  // 1. They haven't submitted anything yet (status is empty)
  // 2. Staff has explicitly allowed modification (status is Modifiable)
  const isInitiallyModifiable = !student.status || student.status === 'Modifiable';
  const [isModifying, setIsModifying] = useState(isInitiallyModifiable);

  const [modReqLoading, setModReqLoading] = useState(false);
  const [modError, setModError] = useState<string | null>(null);

  const [form, setForm] = useState<UniformRequest>({
    shirt: (student.existingShirt as UniformSize) || '',
    trousers: (student.existingTrousers as UniformSize) || '',
    jacket: (student.existingJacket as UniformSize) || '',
    notes: ''
  });

  const handleModRequest = async () => {
    setModReqLoading(true);
    setModError(null);
    try {
      const ok = await requestModification(student.studentId);
      if (ok) {
        const updated = await searchStudent(student.studentId);
        if (updated) onModificationSuccess(updated);
      } else {
        setModError("The request could not be completed. Please contact school support.");
      }
    } catch (err: any) {
      setModError(err.message || "Failed to contact server.");
    } finally {
      setModReqLoading(false);
    }
  };

  const handleRefresh = async () => {
    setModReqLoading(true);
    try {
      const updated = await searchStudent(student.studentId);
      if (updated) onModificationSuccess(updated);
    } finally {
      setModReqLoading(false);
    }
  };

  const hasExistingData = !!(student.existingShirt || student.existingTrousers || student.existingJacket);
  const approvalRequired = config.modification === 'enabled';

  // Wait state: Approval is required AND they have requested it but haven't been granted yet
  const isWaitState = approvalRequired && student.status === 'ModificationRequested';

  // Read only state: They have data, they aren't in modification mode, and staff hasn't already unlocked it
  const showReadOnly = hasExistingData && !isModifying && student.status !== 'Modifiable';

  if (status === 'success') {
    return (
      <div className="bg-white rounded-2xl shadow-soft p-12 border border-green-100 text-center animate-in fade-in zoom-in">
        <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle2 className="h-10 w-10 text-green-500" />
        </div>
        <h3 className="text-2xl font-bold text-gray-900 mb-2">Request Submitted!</h3>
        <p className="text-gray-600 mb-8 max-w-md mx-auto">Thank you. Your uniform sizes have been saved and are pending staff review.</p>
        <button onClick={onReset} className="px-8 py-3 bg-gray-100 text-gray-700 font-bold rounded-xl hover:bg-gray-200 transition-colors">Return to Search</button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Student ID Card */}
      <div className="bg-white rounded-2xl shadow-soft border border-gray-100 overflow-hidden">
        <div className="bg-blue-50/50 px-8 py-4 border-b border-blue-50 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <User className="h-5 w-5 text-blue-600" />
            <h3 className="font-semibold text-blue-900">Student Profile</h3>
          </div>
          {student.status && (
            <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
              student.status === 'Approved' ? 'bg-green-100 text-green-700' : 
              student.status === 'Pending' ? 'bg-blue-100 text-blue-700' : 
              student.status === 'Modifiable' ? 'bg-indigo-100 text-indigo-700' :
              'bg-amber-100 text-amber-700'
            }`}>
              {student.status === 'ModificationRequested' ? 'Wait for Staff Review' : 
               student.status === 'Modifiable' ? 'Ready for Editing' : `Status: ${student.status}`}
            </span>
          )}
        </div>
        <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Student Name</p><p className="text-lg font-bold text-gray-900">{student.englishName}</p></div>
          <div className="text-right font-arabic" dir="rtl"><p className="text-xs font-bold text-gray-400 uppercase tracking-widest" dir="ltr">Arabic Name</p><p className="text-lg font-bold text-gray-900">{student.arabicName}</p></div>
          <div><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Class / Grade</p><p className="text-gray-700 font-medium">{student.grade} - {student.className}</p></div>
          <div className="text-right"><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">ID Reference</p><p className="text-gray-700 font-medium">{student.studentId}</p></div>
        </div>
      </div>

      {isWaitState ? (
        <div className="bg-white rounded-2xl shadow-soft p-12 border border-amber-100 text-center space-y-4">
           <Hourglass className="h-12 w-12 text-amber-500 mx-auto animate-pulse" />
           <h3 className="text-xl font-bold text-gray-900">Approval Required</h3>
           <p className="text-gray-600 max-w-md mx-auto font-medium">
             Your request to modify sizes is pending staff approval. Please check back later.
           </p>
           <div className="pt-4 flex flex-col items-center gap-3">
             <button onClick={handleRefresh} disabled={modReqLoading} className="flex items-center gap-2 px-6 py-2 bg-amber-50 text-amber-700 rounded-xl font-bold border border-amber-200">
               {modReqLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <><RefreshCw className="h-4 w-4" /> Refresh Status</>}
             </button>
             <button onClick={onReset} className="text-gray-400 text-sm hover:underline">Back to Search</button>
           </div>
        </div>
      ) : showReadOnly ? (
        <div className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100 space-y-6">
          <div className="flex items-center justify-between">
             <h3 className="text-xl font-bold text-gray-900">Existing Size Data</h3>
             <button 
                onClick={approvalRequired ? handleModRequest : () => setIsModifying(true)}
                disabled={modReqLoading}
                className="flex items-center gap-2 px-6 py-2 bg-blue-50 text-blue-700 rounded-xl font-bold border border-blue-100"
             >
               {modReqLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <><Edit3 className="h-4 w-4" /> {approvalRequired ? 'Request Modification' : 'Modify Sizes'}</>}
             </button>
          </div>
          {modError && <div className="p-4 bg-red-50 text-red-600 rounded-xl text-xs font-bold flex items-center gap-2"><AlertCircle className="h-4 w-4" /> {modError}</div>}
          <div className="grid grid-cols-3 gap-4">
            <div className="p-4 bg-gray-50 rounded-xl text-center"><p className="text-[10px] text-gray-400 font-bold uppercase">Shirt</p><p className="text-2xl font-black text-gray-900">{student.existingShirt || '-'}</p></div>
            <div className="p-4 bg-gray-50 rounded-xl text-center"><p className="text-[10px] text-gray-400 font-bold uppercase">Trousers</p><p className="text-2xl font-black text-gray-900">{student.existingTrousers || '-'}</p></div>
            <div className="p-4 bg-gray-50 rounded-xl text-center"><p className="text-[10px] text-gray-400 font-bold uppercase">Jacket</p><p className="text-2xl font-black text-gray-900">{student.existingJacket || '-'}</p></div>
          </div>
          <div className="pt-2 text-center">
            <button onClick={onReset} className="text-gray-400 text-xs font-bold hover:text-gray-600">Cancel and Return to Search</button>
          </div>
        </div>
      ) : (
        <form onSubmit={(e) => { e.preventDefault(); onSubmit(form); }} className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100 space-y-8">
          <div className="flex items-center gap-3">
            <ClipboardList className="h-6 w-6 text-blue-600" />
            <h2 className="text-xl font-bold text-gray-900">Select Required Sizes</h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {(['shirt', 'trousers', 'jacket'] as const).map((item) => (
              <div key={item} className="space-y-2">
                <label className="block text-xs font-bold text-gray-700 uppercase tracking-wider">{item}</label>
                <select 
                  value={form[item]} 
                  onChange={(e) => setForm(f => ({ ...f, [item]: e.target.value as UniformSize }))}
                  className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl font-bold"
                  required
                >
                  <option value="">Select Size</option>
                  {UNIFORM_SIZES.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            ))}
          </div>

          <div className="space-y-2">
            <label className="block text-xs font-bold text-gray-700 uppercase tracking-wider">Additional Notes</label>
            <textarea 
              placeholder="Any special fitting requirements..."
              className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl h-24 outline-none focus:ring-2 focus:ring-blue-500"
              value={form.notes} onChange={(e) => setForm(f => ({ ...f, notes: e.target.value }))}
            />
          </div>

          <div className="flex flex-col gap-4">
            <button 
              type="submit" disabled={isSubmitting}
              style={{ backgroundColor: PRIMARY_BLUE }}
              className="w-full py-4 text-white font-bold rounded-xl shadow-lg flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {isSubmitting ? <Loader2 className="h-5 w-5 animate-spin" /> : "Save Uniform Request"}
            </button>
            <button type="button" onClick={onReset} className="w-full py-2 text-gray-400 font-bold text-sm hover:text-gray-600">Cancel</button>
          </div>
        </form>
      )}
    </div>
  );
};

export default RequestForm;

import React, { useState, useEffect } from 'react';
import { fetchAdminRequests, approveRequest, getMessage, updateMessage, fetchSummary, allowEdit } from '../services/api';
import { AdminRequestRow, AdminTab, AppMessage, SizeSummary } from '../types';
import { 
  Lock, Search, Loader2, AlertCircle, RefreshCw, LogOut, MessageSquare, 
  LayoutList, Save, CheckCircle, BarChart3, ToggleLeft, ToggleRight, UserCog
} from 'lucide-react';
import { PRIMARY_BLUE, UNIFORM_SIZES } from '../constants';

const AdminPortal: React.FC = () => {
  const [password, setPassword] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [activeTab, setActiveTab] = useState<AdminTab>(AdminTab.REQUESTS);
  const [isLoading, setIsLoading] = useState(false);
  const [requests, setRequests] = useState<AdminRequestRow[]>([]);
  const [summary, setSummary] = useState<SizeSummary | null>(null);
  const [schoolMessage, setSchoolMessage] = useState<AppMessage>({ english: '', arabic: '', modification: 'enabled' });
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [actionId, setActionId] = useState<number | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      const data = await fetchAdminRequests(password);
      setRequests(data);
      const msg = await getMessage();
      setSchoolMessage(msg);
      setIsLoggedIn(true);
    } catch (err: any) { 
      setError(err.message || 'Login failed.'); 
    } finally { 
      setIsLoading(false); 
    }
  };

  const handleApprove = async (row: number) => {
    setActionId(row);
    try {
      if (await approveRequest(row, password)) {
        setRequests(prev => prev.filter(r => r.row !== row));
      }
    } finally { 
      setActionId(null); 
    }
  };

  const handleAllowEdit = async (row: number) => {
    setActionId(row);
    try {
      if (await allowEdit(row, password)) {
        setRequests(prev => prev.filter(r => r.row !== row));
      }
    } finally { 
      setActionId(null); 
    }
  };

  useEffect(() => {
    if (isLoggedIn && activeTab === AdminTab.SUMMARY) {
      setIsLoading(true);
      fetchSummary(password)
        .then(setSummary)
        .catch(() => setError("Failed to fetch summary"))
        .finally(() => setIsLoading(false));
    }
  }, [activeTab, isLoggedIn, password]);

  if (!isLoggedIn) {
    return (
      <div className="max-w-md mx-auto py-12">
        <div className="bg-white rounded-2xl shadow-soft p-8 border border-gray-100">
          <div className="flex justify-center mb-6">
            <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center">
              <Lock className="h-8 w-8 text-blue-600" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-gray-900 text-center mb-8">Staff Portal</h2>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              placeholder="Admin Password" 
              className="w-full p-4 bg-gray-50 border rounded-xl outline-none text-center focus:ring-2 focus:ring-blue-500 transition-all" 
              value={password} 
              onChange={e => setPassword(e.target.value)} 
              required 
            />
            {error && <p className="text-red-500 text-sm text-center font-medium">{error}</p>}
            <button 
              type="submit" 
              disabled={isLoading} 
              style={{ backgroundColor: PRIMARY_BLUE }} 
              className="w-full py-4 rounded-xl font-bold text-white flex items-center justify-center gap-2 transition-transform active:scale-95"
            >
              {isLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : "Access Dashboard"}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-900">Admin Dashboard</h2>
        <button 
          onClick={() => setIsLoggedIn(false)} 
          className="p-2 text-red-600 font-bold flex items-center gap-2 hover:bg-red-50 rounded-lg transition-colors"
        >
          <LogOut className="h-5 w-5" /> Logout
        </button>
      </div>

      <div className="bg-white p-1 rounded-2xl shadow-sm border border-gray-100 flex gap-1">
        <button onClick={() => setActiveTab(AdminTab.REQUESTS)} className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${activeTab === AdminTab.REQUESTS ? 'bg-blue-600 text-white' : 'text-gray-500 hover:bg-gray-50'}`}>Requests</button>
        <button onClick={() => setActiveTab(AdminTab.SUMMARY)} className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${activeTab === AdminTab.SUMMARY ? 'bg-blue-600 text-white' : 'text-gray-500 hover:bg-gray-50'}`}>Inventory</button>
        <button onClick={() => setActiveTab(AdminTab.MESSAGE)} className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${activeTab === AdminTab.MESSAGE ? 'bg-blue-600 text-white' : 'text-gray-500 hover:bg-gray-50'}`}>Settings</button>
      </div>

      {activeTab === AdminTab.REQUESTS && (
        <div className="bg-white rounded-2xl border border-gray-100 overflow-hidden shadow-soft">
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-gray-50 border-b">
                <tr className="text-xs font-bold text-gray-400 uppercase tracking-widest">
                  <th className="px-6 py-4">Student</th>
                  <th className="px-6 py-4">Action Type</th>
                  <th className="px-6 py-4">Requested Sizes</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {requests.length === 0 ? (
                  <tr><td colSpan={4} className="py-20 text-center text-gray-400 italic">No actions pending at this time.</td></tr>
                ) : requests.map(req => (
                  <tr key={req.row} className="hover:bg-gray-50/50">
                    <td className="px-6 py-4">
                      <div className="font-bold text-gray-900">{req.englishName}</div>
                      <div className="text-xs text-gray-400">{req.studentId} • {req.grade}</div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-md text-[10px] font-bold ${req.requestStatus === 'ModificationRequested' ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
                        {req.requestStatus === 'ModificationRequested' ? 'EDIT REQUEST' : 'NEW SUBMISSION'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm font-bold text-gray-700">
                      S:{req.shirt} T:{req.trousers} J:{req.jacket}
                    </td>
                    <td className="px-6 py-4 text-right">
                      {req.requestStatus === 'ModificationRequested' ? (
                        <button onClick={() => handleAllowEdit(req.row)} disabled={actionId === req.row} className="bg-amber-500 text-white px-4 py-2 rounded-lg text-xs font-bold disabled:opacity-50">
                          {actionId === req.row ? <Loader2 className="h-3 w-3 animate-spin" /> : "Allow Edit"}
                        </button>
                      ) : (
                        <button onClick={() => handleApprove(req.row)} disabled={actionId === req.row} className="bg-green-600 text-white px-4 py-2 rounded-lg text-xs font-bold disabled:opacity-50">
                          {actionId === req.row ? <Loader2 className="h-3 w-3 animate-spin" /> : "Approve"}
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === AdminTab.SUMMARY && summary && (
        <div className="bg-white rounded-2xl border border-gray-100 p-8 shadow-soft">
           <h3 className="text-xl font-bold mb-6">Inventory Overview</h3>
           <table className="w-full text-center">
             <thead>
               <tr className="bg-gray-50 text-xs text-gray-500 uppercase"><th className="px-4 py-3 text-left">Item</th>{UNIFORM_SIZES.map(s => <th key={s}>{s}</th>)}<th className="bg-blue-50">Total</th></tr>
             </thead>
             <tbody className="font-bold divide-y">
               {['shirt', 'trousers', 'jacket'].map(type => (
                 <tr key={type}>
                   <td className="px-4 py-4 text-left capitalize">{type}</td>
                   {UNIFORM_SIZES.map(s => <td key={s} className="text-gray-600">{summary[type as keyof SizeSummary][s] || 0}</td>)}
                   <td className="bg-blue-50 text-blue-700">{Object.values(summary[type as keyof SizeSummary]).reduce((a: any, b: any) => a + b, 0)}</td>
                 </tr>
               ))}
             </tbody>
           </table>
        </div>
      )}

      {activeTab === AdminTab.MESSAGE && (
        <div className="bg-white rounded-2xl border border-gray-100 p-8 space-y-8 shadow-soft">
          <div className="flex items-center justify-between border-b pb-4">
            <h3 className="text-xl font-bold">System Settings</h3>
            <button 
              onClick={() => setSchoolMessage(p => ({ ...p, modification: p.modification === 'enabled' ? 'disabled' : 'enabled' }))}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold border ${schoolMessage.modification === 'enabled' ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-green-50 text-green-700 border-green-200'}`}
            >
              {schoolMessage.modification === 'enabled' ? <ToggleRight /> : <ToggleLeft />}
              Staff Approval for Changes: {schoolMessage.modification === 'enabled' ? 'ON' : 'OFF'}
            </button>
          </div>
          <div className="grid md:grid-cols-2 gap-8">
            <textarea value={schoolMessage.english} onChange={e => setSchoolMessage(p => ({ ...p, english: e.target.value }))} className="p-4 bg-gray-50 border rounded-2xl h-32" placeholder="English Announcement" />
            <textarea dir="rtl" value={schoolMessage.arabic} onChange={e => setSchoolMessage(p => ({ ...p, arabic: e.target.value }))} className="p-4 bg-gray-50 border rounded-2xl h-32 font-arabic text-lg" placeholder="Arabic Announcement" />
          </div>
          <button 
            disabled={isLoading}
            onClick={async () => { 
              setIsLoading(true); 
              if (await updateMessage(schoolMessage, password)) {
                setSuccess('Saved!');
                setTimeout(() => setSuccess(null), 3000);
              }
              setIsLoading(false); 
            }} 
            className="w-full py-4 bg-blue-600 text-white font-bold rounded-xl"
          >
            {isLoading ? <Loader2 className="h-5 w-5 mx-auto animate-spin" /> : "Save Settings"}
          </button>
          {success && <p className="text-green-600 text-center font-bold">{success}</p>}
        </div>
      )}
    </div>
  );
};

export default AdminPortal;

